  return (
    <Alert
      layout="row"
      isNotification
      icon={
        <TriangleAlert className="text-amber-500" size={16} strokeWidth={2} />
      }
      action={
        <Button
          variant="ghost"
          className="group -my-1.5 -me-2 size-8 p-0 hover:bg-transparent"
