          <X
            size={16}
            strokeWidth={2}
            className="opacity-60 transition-opacity group-hover:opacity-100"
          />
        </Button>
      }
    >
      <p className="text-sm">Some information is missing!</p>
    </Alert>
  )
}

export { AlertNotification }
