        </PopoverTrigger>
        <PopoverContent
          align="end"
          className="w-[350px] border border-gray-200 dark:border-gray-800 p-0"
        >
          <ScrollArea className="max-h-80 p-4">
            <div className="space-y-3">
              <div>
                <p className="font-medium text-sm text-gray-800 dark:text-gray-100">
                  {current.title}
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  {current.message}
                </p>
                <p className="text-xs text-muted-foreground mt-1">{current.time}</p>
                {current.cta && (
                  <Link
                    href={current.cta.href}
                    target="_blank"
                    className="text-blue-600 text-sm hover:underline mt-2 inline-block"
                  >
                    {current.cta.text}
                  </Link>
                )}
              </div>
            </div>
          </ScrollArea>

          <div className="flex items-center justify-between border-t border-gray-200 dark:border-gray-800 px-4 py-2">
            <Button
              size="sm"
              variant="ghost"
              onClick={back}
              disabled={step === 0}
            >
              <ChevronLeft className="h-4 w-4 mr-1" />
              Back
            </Button>
            <span className="text-xs text-muted-foreground">
              {step + 1} / {maxSteps}
            </span>
            <Button
              size="sm"
              variant="ghost"
              onClick={next}
              disabled={step === maxSteps - 1}
            >
              Next
              <ChevronRight className="h-4 w-4 ml-1" />
            </Button>
          </div>
        </PopoverContent>
      </Popover>
    </div>
  );
}


