"use client";

import React, {
  createContext,
  useContext,
  useState,
  ReactNode,
  useCallback,
} from "react";
import { Transition } from "@headlessui/react";
import { XMarkIcon } from "@heroicons/react/20/solid";

type ToastVariant = "success" | "error" | "warning" | "info";

interface Toast {
  id: string;
  title: string;
  description?: string;
  variant: ToastVariant;
  duration?: number;
}

interface ToastContextValue {
  addToast: (toast: Omit<Toast, "id">) => void;
}

const ToastContext = createContext<ToastContextValue | undefined>(undefined);

export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used within ToastProvider");
  return ctx;
}

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const removeToast = useCallback((id: string) => {
    setToasts((arr) => arr.filter((t) => t.id !== id));
  }, []);

  const addToast = useCallback(
    ({
      title,
      description,
      variant,
      duration = 4000,
    }: Omit<Toast, "id">) => {
      const id = Date.now().toString();
      setToasts((arr) => [...arr, { id, title, description, variant, duration }]);
      setTimeout(() => removeToast(id), duration);
    },
    [removeToast]
  );

  return (
    <ToastContext.Provider value={{ addToast }}>
      {children}
      <div className="fixed top-5 right-5 space-y-2 z-50">
        {toasts.map((t) => (
          <ToastItem key={t.id} toast={t} onClose={() => removeToast(t.id)} />
        ))}
      </div>
    </ToastContext.Provider>
  );
}

function variantStyles(variant: ToastVariant) {
  switch (variant) {
    case "success":
      return "bg-green-50 border-green-400 text-green-800";
    case "error":
      return "bg-red-50 border-red-400 text-red-800";
    case "warning":
      return "bg-yellow-50 border-yellow-400 text-yellow-800";
    case "info":
    default:
      return "bg-blue-50 border-blue-400 text-blue-800";
  }
}

function ToastItem({
  toast,
  onClose,
}: {
  toast: Toast;
  onClose: () => void;
}) {
  return (
    <Transition
      appear
      show
      as={React.Fragment}
      enter="transform transition duration-200"
      enterFrom="opacity-0 translate-y-2"
      enterTo="opacity-100 translate-y-0"
      leave="transform transition duration-150"
      leaveFrom="opacity-100 translate-y-0"
      leaveTo="opacity-0 translate-y-2"
    >
      <div
        className={`max-w-sm w-full border-l-4 ${variantStyles(
          toast.variant
        )} shadow-lg rounded p-4 flex`}
        role="alert"
        aria-live="assertive"
      >
        <div className="flex-1">
          <p className="font-semibold">{toast.title}</p>
          {toast.description && <p className="text-sm mt-1">{toast.description}</p>}
        </div>
        <button
          onClick={onClose}
          className="ml-3 text-gray-500 hover:text-gray-700 focus:outline-none"
          aria-label="Close notification"
        >
          <XMarkIcon className="h-5 w-5" />
        </button>
      </div>
    </Transition>
  );
}


