      <div className="space-x-2">
        {["success", "error", "warning", "info"].map((v) => (
          <button
            key={v}
            onClick={() => trigger(v as any)}
            className={`px-4 py-2 rounded font-medium focus:outline-none focus:ring-2 ${
              {
                success:
                  "bg-green-600 text-white hover:bg-green-700 focus:ring-green-300",
