                    .map(({ id, variant, title, description, styleVariant }) => (
                    <AlertToast
                        key={id}
                        variant={variant}
                        styleVariant={styleVariant}
                        title={title}
                        description={description}
                        onClose={() => handleClose(id)}
                    />
                    ))}
                </AnimatePresence>
            </div>

            {/* Default Style Column */}
            <div className="space-y-4 w-full max-w-sm">
                <AnimatePresence>
                {alerts
